1	import SwiftUI
2	import AIUsagesTrackersLib
3	
4	/// Scrollable popover anchored to the menu bar item; uses LazyVStack + maxHeight
5	/// so the popover does not stretch unboundedly when many accounts are present.
6	struct UsageDetailsView: View {
7	    let store: UsageStore
8	    let refreshState: RefreshState
9	    let historyReader: UsageHistoryReader
10	    let onRefresh: () async -> Void
11	    let onOpenSettings: () -> Void
12	    let onQuit: () -> Void
13	
14	    @State private var contentMode: PopoverContentMode = .list
15	    @State private var selectedHistoryWindow: UsageHistoryTimeWindow = .twentyFourHours
16	    @State private var historySnapshot: UsageHistorySnapshot = .empty
17	    @State private var historyReferenceDate = Date()
18	    @State private var historyWindowEndDate: Date?
19	    @State private var isLoadingHistory = false
20	
21	    private static let popoverWidth: CGFloat = 320
22	    private static let maxScreenHeightRatio: CGFloat = 0.9
23	    private static let fallbackScreenHeight: CGFloat = 800
24	    private static let historyAutoRefreshInterval: Duration = .seconds(60)
25	    /// Reserved for header + footer + dividers so the full popover stays within the ratio cap.
26	    private static let chromeHeightReserve: CGFloat = 80
27	
28	    private var maxScrollHeight: CGFloat {
29	        let screenHeight = NSScreen.main?.visibleFrame.height ?? Self.fallbackScreenHeight
30	        return screenHeight * Self.maxScreenHeightRatio - Self.chromeHeightReserve
31	    }
32	
33	    var body: some View {
34	        VStack(spacing: 0) {
35	            header
36	
37	            Divider()
38	
39	            content
40	
41	            Divider()
42	
43	            footer
44	        }
45	        .frame(width: Self.popoverWidth)
46	        .task(id: historyTaskID) {
47	            await runHistoryRefreshLoopIfNeeded()
48	        }
49	    }
50	
51	    private var historyTaskID: String {
52	        "\(contentMode.rawValue)-\(selectedHistoryWindow.rawValue)"
53	    }
54	
55	    /// Returns a map of vendor → first index in sorted, for vendors that have active outages.
56	    private func vendorsNeedingBanner(in sorted: [VendorUsageEntry]) -> [Vendor: Int] {
57	        var result: [Vendor: Int] = [:]
58	        for (index, entry) in sorted.enumerated() where result[entry.vendor] == nil {
59	            if store.outagesByVendor[entry.vendor] != nil {
60	                result[entry.vendor] = index
61	            }
62	        }
63	        return result
64	    }
65	
66	    // MARK: - Subviews
67	
68	    @ViewBuilder
69	    private var content: some View {
70	        switch contentMode {
71	        case .list:
72	            listingContent
73	        case .chart:
74	            chartContent
75	        }
76	    }
77	
78	    @ViewBuilder
79	    private var listingContent: some View {
80	        let sorted = store.entries.sortedForDisplay()
81	        if sorted.isEmpty {
82	            emptyState
83	        } else {
84	            ScrollView {
85	                LazyVStack(spacing: 8) {
86	                    // Track which vendors have already shown their status banner
87	                    // using a running cursor — entries are sorted by vendor so
88	                    // entries of the same vendor are contiguous.
89	                    let vendorsWithBanner = vendorsNeedingBanner(in: sorted)
90	                    ForEach(Array(sorted.enumerated()), id: \.element.id) { index, entry in
91	                        if vendorsWithBanner[entry.vendor] == index,
92	                           let outages = store.outagesByVendor[entry.vendor] {
93	                            VendorStatusBanner(outages: outages)
94	                        }
95	                        AccountCardView(
96	                            entry: entry,
97	                            isRefreshing: refreshState.isRefreshing(
98	                                vendor: entry.vendor,
99	                                account: entry.account
100	                            )
101	                        )
102	                    }
103	                }
104	                .padding(12)
105	            }
106	            .frame(maxHeight: maxScrollHeight)
107	            .background(Color(NSColor.windowBackgroundColor).opacity(0.4))
108	        }
109	    }
110	
111	    private var chartContent: some View {
112	        ScrollView {
113	            UsageHistoryChartView(
114	                snapshot: historySnapshot,
115	                referenceDate: historyReferenceDate,
116	                selectedWindow: historyWindowBinding,
117	                isLoading: isLoadingHistory,
118	                configurations: AppDelegate.sharedPreferences.chartConfigurations,
119	                currentEntries: store.entries,
120	                onPreviousWindow: {
121	                    Task { await moveHistoryWindow(direction: .previous) }
122	                },
123	                onNextWindow: {
124	                    Task { await moveHistoryWindow(direction: .next) }
125	                }
126	            )
127	        }
128	        .frame(maxHeight: maxScrollHeight)
129	        .background(Color(NSColor.windowBackgroundColor).opacity(0.4))
130	    }
131	
132	    private var historyWindowBinding: Binding<UsageHistoryTimeWindow> {
133	        Binding(
134	            get: { selectedHistoryWindow },
135	            set: { newValue in
136	                selectedHistoryWindow = newValue
137	                historyWindowEndDate = nil
138	            }
139	        )
140	    }
141	
142	    private var header: some View {
143	        let refreshing = !refreshState.inFlight.isEmpty
144	        return HStack(spacing: 8) {
145	            Button {
146	                onOpenSettings()
147	            } label: {
148	                Image(systemName: "gearshape")
149	                    .frame(width: 16, height: 16)
150	                    .hoverAffordance()
151	            }
152	            .buttonStyle(.borderless)
153	            .controlSize(.small)
154	            .help("Settings")
155	            .keyboardShortcut(",", modifiers: .command)
156	            .focusable(false)
157	
158	            Spacer()
159	
160	            Text("AI Usages Tracker")
161	                .font(.system(size: 11, weight: .medium))
162	                .foregroundStyle(.secondary)
163	
164	            Spacer()
165	
166	            Button {
167	                guard !refreshing else { return }
168	                Task { await onRefresh() }
169	            } label: {
170	                ZStack {
171	                    if refreshing {
172	                        ProgressView()
173	                            .controlSize(.small)
174	                            .scaleEffect(0.6)
175	                    } else {
176	                        Image(systemName: "arrow.clockwise")
177	                    }
178	                }
179	                .frame(width: 16, height: 16)
180	                .hoverAffordance(isEnabled: !refreshing)
181	            }
182	            .buttonStyle(.borderless)
183	            .controlSize(.small)
184	            .disabled(refreshing)
185	            .help("Refresh usage data")
186	            .keyboardShortcut("r")
187	            .focusable(false)
188	        }
189	        .padding(.horizontal, 12)
190	        .padding(.vertical, 8)
191	    }
192	
193	    @ViewBuilder
194	    private var emptyState: some View {
195	        if AppDelegate.sharedPreferences.menuBarSegments.isEmpty {
196	            unconfiguredEmptyState
197	        } else {
198	            VStack(spacing: 8) {
199	                Text("No usage data")
200	                    .font(.system(size: 12, weight: .medium))
201	                    .foregroundStyle(.secondary)
202	                Text("Waiting for data...")
203	                    .font(.system(size: 11))
204	                    .foregroundStyle(.tertiary)
205	            }
206	            .frame(maxWidth: .infinity)
207	            .padding(.vertical, 32)
208	        }
209	    }
210	
211	    private var unconfiguredEmptyState: some View {
212	        VStack(spacing: 12) {
213	            Image(systemName: "gearshape.2")
214	                .font(.system(size: 28, weight: .light))
215	                .foregroundStyle(.secondary)
216	            Text("No menu bar segment yet")
217	                .font(.system(size: 12, weight: .medium))
218	                .foregroundStyle(.primary)
219	            Text("Add your first segment to start tracking your AI usages directly from the menu bar.")
220	                .font(.system(size: 11))
221	                .foregroundStyle(.secondary)
222	                .multilineTextAlignment(.center)
223	                .fixedSize(horizontal: false, vertical: true)
224	            Button {
225	                onOpenSettings()
226	            } label: {
227	                Text("Open Settings")
228	            }
229	            .controlSize(.small)
230	        }
231	        .frame(maxWidth: .infinity)
232	        .padding(.horizontal, 24)
233	        .padding(.vertical, 24)
234	    }
235	
236	    private var footer: some View {
237	        HStack {
238	            Picker("Popover content", selection: $contentMode) {
239	                Image(systemName: "list.bullet")
240	                    .tag(PopoverContentMode.list)
241	                Image(systemName: "chart.xyaxis.line")
242	                    .tag(PopoverContentMode.chart)
243	            }
244	            .pickerStyle(.segmented)
245	            .labelsHidden()
246	            .controlSize(.mini)
247	            .frame(width: 62)
248	            .help("Switch between usage list and history chart")
249	            .focusable(false)
250	
251	            Spacer()
252	
253	            Button {
254	                onQuit()
255	            } label: {
256	                Text("Quit")
257	                    .hoverAffordance()
258	            }
259	            .buttonStyle(.borderless)
260	            .keyboardShortcut("q")
261	            .controlSize(.small)
262	            .focusable(false)
263	        }
264	        .padding(.horizontal, 12)
265	        .padding(.vertical, 8)
266	    }
267	
268	    @MainActor
269	    private func runHistoryRefreshLoopIfNeeded() async {
270	        guard contentMode == .chart else { return }
271	        while !Task.isCancelled {
272	            await loadHistory()
273	            do {
274	                try await Task.sleep(for: Self.historyAutoRefreshInterval)
275	            } catch {
276	                break
277	            }
278	        }
279	    }
280	
281	    @MainActor
282	    private func loadHistory() async {
283	        let requestedWindow = selectedHistoryWindow
284	        let requestedEndDate = historyWindowEndDate
285	        let requestedDate = requestedEndDate ?? Date()
286	        isLoadingHistory = true
287	        let snapshot = await historyReader.load(window: requestedWindow, now: requestedDate)
288	        guard contentMode == .chart,
289	              selectedHistoryWindow == requestedWindow,
290	              historyWindowEndDate == requestedEndDate else {
291	            isLoadingHistory = false
292	            return
293	        }
294	        historySnapshot = snapshot
295	        historyReferenceDate = requestedDate
296	        isLoadingHistory = false
297	    }
298	
299	    @MainActor
300	    private func moveHistoryWindow(direction: HistoryWindowDirection) async {
301	        guard let interval = selectedHistoryWindow.timeInterval else { return }
302	        let currentEndDate = historyReferenceDate
303	        let targetEndDate: Date
304	        switch direction {
305	        case .previous:
306	            targetEndDate = currentEndDate.addingTimeInterval(-interval)
307	        case .next:
308	            targetEndDate = min(currentEndDate.addingTimeInterval(interval), Date())
309	        }
310	        guard targetEndDate != currentEndDate else { return }
311	        historyWindowEndDate = targetEndDate
312	        await loadHistory()
313	    }
314	}
315	
316	private enum PopoverContentMode: String, Hashable {
317	    case list
318	    case chart
319	}
