import Foundation

// MARK: - Remaining time formatting

private let secondsPerMinute = 60
private let secondsPerHour = 3600
private let secondsPerDay = 86400

/// Formats the remaining time until `resetAt` as a compact string (e.g. "2d 5h 13m").
/// Returns `"--"` when `resetAt` cannot be parsed, `"0m"` when the reset date has passed.
public func formatRemainingTime(resetAt: ISODate, now: Date) -> String {
    guard let resetDate = resetAt.date else { return "--" }
    let totalSeconds = Int(resetDate.timeIntervalSince(now))
    guard totalSeconds > 0 else { return "0m" }

    let days = totalSeconds / secondsPerDay
    let hours = (totalSeconds % secondsPerDay) / secondsPerHour
    let minutes = (totalSeconds % secondsPerHour) / secondsPerMinute

    var parts: [String] = []
    if days > 0 { parts.append("\(days)d") }
    if hours > 0 { parts.append("\(hours)h") }
    if minutes > 0 || parts.isEmpty { parts.append("\(minutes)m") }
    return parts.joined(separator: " ")
}

// MARK: - Theoretical fraction

/// Fraction of the time window that has elapsed, clamped to 0...1.
/// Returns 0 when `resetAt` cannot be parsed or `windowDuration` is zero.
public func theoreticalFraction(resetAt: ISODate, windowDuration: DurationMinutes, now: Date) -> Double {
    guard let resetDate = resetAt.date else { return 0 }
    let windowSeconds = Double(windowDuration.rawValue) * 60
    guard windowSeconds > 0 else { return 0 }
    let windowStart = resetDate.addingTimeInterval(-windowSeconds)
    let elapsed = now.timeIntervalSince(windowStart)
    return min(max(elapsed / windowSeconds, 0), 1)
}

// MARK: - Reset date formatting

/// Formats the reset date relative to `now`:
/// - same calendar day → time only ("HH:mm")
/// - next calendar day → "tomorrow HH:mm"
/// - otherwise → "MMM d, HH:mm"
/// Returns "--" when `resetAt` cannot be parsed.
public func formatResetDate(_ resetAt: ISODate, now: Date) -> String {
    guard let resetDate = resetAt.date else { return "--" }
    let calendar = Calendar.current
    let today = calendar.startOfDay(for: now)
    let resetDay = calendar.startOfDay(for: resetDate)
    let timeString = ResetDateFormatting.timeFormatter.string(from: resetDate)
    if resetDay == today {
        return "@ \(timeString)"
    }
    let tomorrow = calendar.date(byAdding: .day, value: 1, to: today)!
    if resetDay == tomorrow {
        return "Tomorrow @ \(timeString)"
    }
    return ResetDateFormatting.dateTimeFormatter.string(from: resetDate)
}

// Singletons are safe: only called from @MainActor SwiftUI views
private enum ResetDateFormatting {
    static let timeFormatter: DateFormatter = {
        let f = DateFormatter()
        f.dateFormat = "HH:mm"
        return f
    }()

    static let dateTimeFormatter: DateFormatter = {
        let f = DateFormatter()
        f.dateFormat = "MMM d '@' HH:mm"
        return f
    }()
}

// MARK: - Consumption tier

/// Severity tiers for consumption ratio (actual / theoretical pace).
/// Ordered by severity so `Comparable` yields the worst tier via `max()`.
public enum ConsumptionTier: Int, Comparable, Sendable, CaseIterable {
    case comfortable  // < 0.7
    case onTrack      // [0.7, 0.9)
    case approaching  // [0.9, 1.0)
    case over         // [1.0, 1.2)
    case critical     // [1.2, 1.6)
    case exhausted    // >= 1.6

    public static func < (lhs: ConsumptionTier, rhs: ConsumptionTier) -> Bool {
        lhs.rawValue < rhs.rawValue
    }

    private static let comfortableUpperBound = 0.7
    private static let onTrackUpperBound = 0.9
    private static let approachingUpperBound = 1.0
    private static let overUpperBound = 1.2
    private static let criticalUpperBound = 1.6
}

/// Maps a consumption ratio to the appropriate severity tier.
public func consumptionTier(ratio: Double) -> ConsumptionTier {
    switch ratio {
    case ..<0.7:       return .comfortable
    case ..<0.9:       return .onTrack
    case ..<1.0:       return .approaching
    case ..<1.2:       return .over
    case ..<1.6:       return .critical
    default:           return .exhausted
    }
}

/// Computes the consumption ratio: how fast actual usage is relative to theoretical pace.
/// Returns `nil` when `theoreticalFraction` is zero or negative (window not started).
public func consumptionRatio(actualPercent: UsagePercent, theoreticalFraction: Double) -> Double? {
    guard theoreticalFraction > 0 else { return nil }
    return Double(actualPercent.rawValue) / (theoreticalFraction * 100.0)
}

// MARK: - Entry sorting

extension Array where Element == VendorUsageEntry {
    /// Sorted by vendor name, then active-first within each vendor, then account name.
    public func sortedForDisplay() -> [VendorUsageEntry] {
        sorted { lhs, rhs in
            if lhs.vendor.rawValue != rhs.vendor.rawValue {
                return lhs.vendor.rawValue < rhs.vendor.rawValue
            }
            if lhs.isActive != rhs.isActive {
                return lhs.isActive
            }
            return lhs.account.rawValue < rhs.account.rawValue
        }
    }

    /// Set of vendors that appear more than once in the array.
    public func vendorsWithMultipleAccounts() -> Set<Vendor> {
        var counts: [Vendor: Int] = [:]
        for entry in self {
            counts[entry.vendor, default: 0] += 1
        }
        return Set(counts.filter { $0.value > 1 }.keys)
    }
}

# Swift value objects

## Prefer value objects over primitive types for domain concepts

Representing domain concepts as plain `String` or `Int` makes APIs ambiguous and allows values to be accidentally swapped. Introduce a value object (a struct wrapping a primitive) whenever a field has a distinct identity or constrained meaning.

Typical candidates in this codebase:
- Email addresses, vendor names, ISO dates — wrap `String`
- Percentages, durations in a fixed unit — wrap `Int`
- Type discriminators with a closed set — use a `String` enum

```swift
// BAD — impossible to tell which String is which at the call site
func updateIsActive(vendor: String, activeAccount: String?) { ... }
updateIsActive(vendor: "claude", activeAccount: "user@example.com")

// GOOD — self-documenting, type-checked
func updateIsActive(vendor: Vendor, activeAccount: AccountEmail?) { ... }
updateIsActive(vendor: .claude, activeAccount: "user@example.com")
```

## Use a struct, not an enum, for open-ended string domains

Use a `struct` when new values can appear without a code change (e.g., vendor names, error codes). Name each known value as a `static let` constant. Unknown values decode transparently without throwing.

```swift
public struct Vendor: RawRepresentable, Codable, Equatable, Hashable, Sendable {
    public let rawValue: String
    public init(rawValue: String) { self.rawValue = rawValue }

    public static let claude = Vendor(rawValue: "claude")
}
```

Use a `enum` only when the set is closed and an unknown value must be a decode error (e.g., a JSON discriminator).

## Implement Codable manually — the default synthesis does not work for RawRepresentable structs

`JSONEncoder`/`JSONDecoder` do not synthesise `Codable` conformance for custom structs that are `RawRepresentable`. Implement the two methods explicitly:

```swift
public init(from decoder: Decoder) throws {
    rawValue = try decoder.singleValueContainer().decode(String.self)
}

public func encode(to encoder: Encoder) throws {
    var container = encoder.singleValueContainer()
    try container.encode(rawValue)
}
```

## Add ExpressibleByXxxLiteral for ergonomic call sites

String-based value objects should conform to `ExpressibleByStringLiteral`; integer-based ones to `ExpressibleByIntegerLiteral`. This keeps call sites and tests readable without sacrificing type safety.

```swift
extension AccountEmail: ExpressibleByStringLiteral {
    public init(stringLiteral value: String) { rawValue = value }
}

// Callers and tests look the same as before
let entry = VendorUsageEntry(vendor: "claude", account: "user@example.com")
dict["user@example.com"]  // subscript resolves to AccountEmail via ExpressibleByStringLiteral
```

Without this conformance, every call site needs an explicit `AccountEmail(rawValue: "...")` constructor — correct but noisy.

## Add CustomStringConvertible for clean logging

Value objects used in log messages should implement `CustomStringConvertible` and return `rawValue` as their description. Without this, string interpolation would print the struct's default representation (`Vendor(rawValue: "claude")` instead of `claude`).

```swift
extension Vendor: CustomStringConvertible {
    public var description: String { rawValue }
}
```

## Add domain behaviour as computed properties

When a value object stores a string that needs parsing (e.g., an ISO date), expose a computed property rather than requiring callers to parse it themselves. This centralises the parsing logic.

```swift
public struct ISODate: RawRepresentable, ... {
    public let rawValue: String

    /// Returns nil if the stored string is not a parseable ISO 8601 date.
    public var date: Date? {
        // New formatter per call — ISO8601DateFormatter is not thread-safe; acceptable for this cold path
        ISO8601DateFormatter().date(from: rawValue)
    }

    public init(date: Date) {
        // New formatter per call — acceptable for this cold path
        rawValue = ISO8601DateFormatter().string(from: date)
    }
}
```

Do not share a static `ISO8601DateFormatter` from inside a value-type method; value types have no isolation boundary. Creating one per call is thread-safe and acceptable for cold paths (see `docs/SWIFT-CONCURRENCY.md`).

## Add Comparable where ordering makes sense

For quantity wrappers (`UsagePercent`, `DurationMinutes`), add `Comparable` by delegating to `rawValue`. This enables `min`, `max`, `sort`, and `<` comparisons in business logic.

```swift
public static func < (lhs: UsagePercent, rhs: UsagePercent) -> Bool {
    lhs.rawValue < rhs.rawValue
}
```

## Value object checklist

When introducing a new domain field, ask:

| Question | If yes |
|---|---|
| Can two fields of this type be accidentally swapped? | Wrap in a value object |
| Can new values appear at runtime without a code change? | Use a `struct`, not an `enum` |
| Is the raw value compared frequently in tests? | Add `ExpressibleByXxxLiteral` |
| Is the value used in log messages? | Add `CustomStringConvertible` |
| Does the raw value need parsing into another type? | Add a computed property |
| Does ordering between values make sense? | Conform to `Comparable` |

import Foundation
import Testing
@testable import AIUsagesTrackersLib

// MARK: - Helpers

private func date(_ iso: String) -> Date {
    ISO8601DateFormatter().date(from: iso)!
}

// MARK: - formatRemainingTime

@Suite("formatRemainingTime")
struct FormatRemainingTimeTests {

    @Test("returns '--' for unparseable ISODate")
    func invalidDate() {
        let result = formatRemainingTime(resetAt: ISODate(rawValue: "not-a-date"), now: Date())
        #expect(result == "--")
    }

    @Test("returns '0m' when reset is in the past")
    func pastDate() {
        let now = date("2026-04-17T15:00:00Z")
        let result = formatRemainingTime(resetAt: ISODate(rawValue: "2026-04-17T14:00:00Z"), now: now)
        #expect(result == "0m")
    }

    @Test("returns '0m' when reset is exactly now")
    func exactlyNow() {
        let now = date("2026-04-17T15:00:00Z")
        let result = formatRemainingTime(resetAt: ISODate(rawValue: "2026-04-17T15:00:00Z"), now: now)
        #expect(result == "0m")
    }

    @Test("formats minutes only")
    func minutesOnly() {
        let now = date("2026-04-17T14:55:00Z")
        let result = formatRemainingTime(resetAt: ISODate(rawValue: "2026-04-17T15:00:00Z"), now: now)
        #expect(result == "5m")
    }

    @Test("formats hours and minutes")
    func hoursAndMinutes() {
        let now = date("2026-04-17T12:47:00Z")
        let result = formatRemainingTime(resetAt: ISODate(rawValue: "2026-04-17T15:00:00Z"), now: now)
        #expect(result == "2h 13m")
    }

    @Test("formats days, hours, and minutes")
    func daysHoursMinutes() {
        let now = date("2026-04-17T00:00:00Z")
        let result = formatRemainingTime(resetAt: ISODate(rawValue: "2026-04-20T05:30:00Z"), now: now)
        #expect(result == "3d 5h 30m")
    }

    @Test("formats exactly 1 day")
    func exactlyOneDay() {
        let now = date("2026-04-17T00:00:00Z")
        let result = formatRemainingTime(resetAt: ISODate(rawValue: "2026-04-18T00:00:00Z"), now: now)
        #expect(result == "1d")
    }
}

// MARK: - theoreticalFraction

@Suite("theoreticalFraction")
struct TheoreticalFractionTests {

    @Test("returns 0 for unparseable ISODate")
    func invalidDate() {
        let result = theoreticalFraction(
            resetAt: ISODate(rawValue: "bad"),
            windowDuration: DurationMinutes(rawValue: 300),
            now: Date()
        )
        #expect(result == 0)
    }

    @Test("returns 0 for zero window duration")
    func zeroDuration() {
        let result = theoreticalFraction(
            resetAt: ISODate(rawValue: "2026-04-17T15:00:00Z"),
            windowDuration: DurationMinutes(rawValue: 0),
            now: date("2026-04-17T14:00:00Z")
        )
        #expect(result == 0)
    }

    @Test("returns 0.5 at midpoint of window")
    func midpoint() {
        // Window: 300 min = 5h. Reset at 15:00 → start at 10:00. Now at 12:30 → 2.5h elapsed = 0.5
        let result = theoreticalFraction(
            resetAt: ISODate(rawValue: "2026-04-17T15:00:00Z"),
            windowDuration: DurationMinutes(rawValue: 300),
            now: date("2026-04-17T12:30:00Z")
        )
        #expect(abs(result - 0.5) < 0.001)
    }

    @Test("clamps to 1.0 when reset is in the past")
    func pastReset() {
        let result = theoreticalFraction(
            resetAt: ISODate(rawValue: "2026-04-17T10:00:00Z"),
            windowDuration: DurationMinutes(rawValue: 300),
            now: date("2026-04-17T15:00:00Z")
        )
        #expect(result == 1.0)
    }

    @Test("clamps to 0.0 before window starts")
    func beforeWindow() {
        // Window: 60 min. Reset at 15:00 → start at 14:00. Now at 13:00 → before start
        let result = theoreticalFraction(
            resetAt: ISODate(rawValue: "2026-04-17T15:00:00Z"),
            windowDuration: DurationMinutes(rawValue: 60),
            now: date("2026-04-17T13:00:00Z")
        )
        #expect(result == 0.0)
    }
}

// MARK: - formatResetDate

@Suite("formatResetDate")
struct FormatResetDateTests {

    // Fixed UTC reference: 2026-04-18T10:00:00Z
    private static let now = Date(timeIntervalSince1970: 1_776_513_600)

    @Test("returns '--' for unparseable ISODate")
    func invalidDate() {
        let result = formatResetDate(ISODate(rawValue: "bad"), now: Self.now)
        #expect(result == "--")
    }

    @Test("shows '@ HH:mm' when reset is today")
    func today() {
        // Same UTC day as now: 2026-04-18T15:00:00Z
        let result = formatResetDate(ISODate(rawValue: "2026-04-18T15:00:00Z"), now: Self.now)
        #expect(result.hasPrefix("@ "))
        #expect(!result.contains("Apr"))
        #expect(!result.contains("Tomorrow"))
    }

    @Test("shows 'Tomorrow @ HH:mm' when reset is the next calendar day")
    func tomorrow() {
        // Next UTC day: 2026-04-19T08:00:00Z
        let result = formatResetDate(ISODate(rawValue: "2026-04-19T08:00:00Z"), now: Self.now)
        #expect(result.hasPrefix("Tomorrow @ "))
        #expect(!result.contains("Apr"))
    }

    @Test("shows full date when reset is two or more days away")
    func laterDate() {
        // Two days later: 2026-04-20T08:00:00Z
        let result = formatResetDate(ISODate(rawValue: "2026-04-20T08:00:00Z"), now: Self.now)
        #expect(result != "--")
        #expect(!result.hasPrefix("tomorrow"))
        #expect(!result.contains("today"))
    }
}

// MARK: - sortedForDisplay

@Suite("sortedForDisplay")
struct SortedForDisplayTests {

    private func entry(vendor: String, account: String, isActive: Bool = false) -> VendorUsageEntry {
        VendorUsageEntry(
            vendor: Vendor(rawValue: vendor),
            account: AccountEmail(rawValue: account),
            isActive: isActive
        )
    }

    @Test("empty array returns empty")
    func emptyArray() {
        let result: [VendorUsageEntry] = [].sortedForDisplay()
        #expect(result.isEmpty)
    }

    @Test("single entry returns itself")
    func singleEntry() {
        let entries = [entry(vendor: "claude", account: "a@b.com")]
        let result = entries.sortedForDisplay()
        #expect(result.count == 1)
        #expect(result[0].vendor.rawValue == "claude")
    }

    @Test("sorts by vendor name alphabetically")
    func sortsByVendor() {
        let entries = [
            entry(vendor: "openai", account: "x@y.com"),
            entry(vendor: "claude", account: "a@b.com"),
        ]
        let result = entries.sortedForDisplay()
        #expect(result[0].vendor.rawValue == "claude")
        #expect(result[1].vendor.rawValue == "openai")
    }

    @Test("active entries come first within same vendor")
    func activeFirst() {
        let entries = [
            entry(vendor: "claude", account: "inactive@b.com", isActive: false),
            entry(vendor: "claude", account: "active@b.com", isActive: true),
        ]
        let result = entries.sortedForDisplay()
        #expect(result[0].isActive == true)
        #expect(result[1].isActive == false)
    }

    @Test("sorts by account alphabetically within same vendor and activity")
    func sortsByAccount() {
        let entries = [
            entry(vendor: "claude", account: "z@b.com", isActive: true),
            entry(vendor: "claude", account: "a@b.com", isActive: true),
        ]
        let result = entries.sortedForDisplay()
        #expect(result[0].account.rawValue == "a@b.com")
        #expect(result[1].account.rawValue == "z@b.com")
    }

    @Test("full three-level sort")
    func threeLevelSort() {
        let entries = [
            entry(vendor: "openai", account: "x@y.com", isActive: true),
            entry(vendor: "claude", account: "z@b.com", isActive: false),
            entry(vendor: "claude", account: "a@b.com", isActive: true),
            entry(vendor: "claude", account: "m@b.com", isActive: true),
        ]
        let result = entries.sortedForDisplay()
        // Claude active first (a, m), then claude inactive (z), then openai
        #expect(result[0].account.rawValue == "a@b.com")
        #expect(result[1].account.rawValue == "m@b.com")
        #expect(result[2].account.rawValue == "z@b.com")
        #expect(result[3].vendor.rawValue == "openai")
    }
}

